from llama_stack import LlamaSafetyFilter
import vex

@vex.verify()
def detect_safety_false_positive(response: dict, original_prompt: str) -> dict:
    safety_result = response.get('safety_check')
    if safety_result and safety_result.get('blocked'):
        # Check if content is actually benign
        benign_indicators = ['support', 'help', 'question', 'price']
        is_benign = any(indicator in original_prompt.lower() for indicator in benign_indicators)

        if is_benign:
            return {
                'issue': 'SAFETY_FALSE_POSITIVE',
                'confidence': 0.92,
                'metadata': {
                    'blocked_reason': safety_result.get('reason'),
                    'prompt_length': len(original_prompt)
                }
            }
    return {'issue': 'PASS'}

# Usage in Llama Stack agent
safety_filter = LlamaSafetyFilter()
result = safety_filter.check(prompt)
observed = detect_safety_false_positive(result, prompt)

from llama_stack import LlamaAgentLoop
import vex

@vex.verify()
def detect_loop_exhaustion(loop_state: dict) -> dict:
    turns_used = loop_state.get('turn_count', 0)
    max_turns = loop_state.get('config', {}).get('max_turns', 20)
    task_complete = loop_state.get('task_status') == 'COMPLETED'

    if turns_used >= max_turns * 0.9 and not task_complete:
        return {
            'issue': 'LOOP_EXHAUSTION',
            'confidence': min(turns_used / max_turns, 1.0),
            'metadata': {
                'turns_used': turns_used,
                'max_turns': max_turns,
                'last_action': loop_state.get('last_action')
            }
        }
    return {'issue': 'PASS'}

# In agent loop
agent_loop = LlamaAgentLoop()
loop_state = agent_loop.run(task)
observed = detect_loop_exhaustion(loop_state)

from llama_stack import LlamaToolExecutor
import json
import vex

@vex.verify()
def validate_tool_schema(tool_response: dict) -> dict:
    expected_schema = {
        'type': 'object',
        'required': ['result', 'schema_version'],
        'properties': {
            'result': {'type': 'object'},
            'schema_version': {'type': 'string', 'pattern': '^1\.0$'}
        }
    }

    try:
        if 'result' not in tool_response or 'schema_version' not in tool_response:
            return {
                'issue': 'SCHEMA_MISSING_FIELDS',
                'confidence': 1.0,
                'metadata': {'missing': ['result', 'schema_version']}
            }

        if tool_response['schema_version'] != '1.0':
            return {
                'issue': 'SCHEMA_VERSION_MISMATCH',
                'confidence': 0.95,
                'metadata': {'actual': tool_response['schema_version']}
            }
    except Exception as e:
        return {'issue': 'SCHEMA_PARSE_ERROR', 'confidence': 0.98, 'error': str(e)}

    return {'issue': 'PASS'}

tool_executor = LlamaToolExecutor()
response = tool_executor.execute('search', {'query': 'llama stack'})
observed = validate_tool_schema(response)

