from llama_stack import LlamaToolExecutor

def normalize_tool_response(raw_response: dict) -> dict:
    normalized = {
        'result': raw_response.get('data', raw_response),
        'schema_version': '1.0',
        'tool_name': raw_response.get('tool', 'unknown'),
        'success': raw_response.get('error') is None
    }

    # Handle common Llama Stack tool formats
    if 'documents' in raw_response:
        normalized['result'] = {'type': 'search', 'docs': raw_response['documents']}
    elif 'calculation' in raw_response:
        normalized['result'] = {'type': 'calc', 'value': raw_response['calculation']}

    return normalized

# Integration wrapper
tool_executor = LlamaToolExecutor()
raw_result = tool_executor.execute('search', {'query': 'llama agents'})
normalized = normalize_tool_response(raw_result)

print(f"Raw: {raw_result.keys()}")
print(f"Normalized: {list(normalized.keys())}")
